def format_mikan_content():
    lines = MIKAN_CONTENT.strip().split('\n')
    formatted = []
    for line in lines:
        if line.startswith('星期') or line in ['剧场版', 'OVA']:
            formatted.append(f"\n### {line}\n")
        elif line.strip().startswith('-'):
            formatted.append(line)
    return '\n'.join(formatted)

def create_mikan_tab():
    with gr.TabItem("📺 米咔动漫更新"):
        gr.Markdown("## 📺 最新动漫更新列表（来自 mikanani.kas.pub）")
        gr.Markdown(format_mikan_content())
        gr.Markdown("\n> 💡 提示：可复制番剧名，在「AI打标」或「保留标签」中自动置顶")